uniform highp usampler2D batchingIdTexture;


float getIndirectIndex( const in int i ) {

int size = textureSize( batchingIdTexture, 0 ).x;
int x = i % size;
int y = i / size;
return float( texelFetch( batchingIdTexture, ivec2( x, y ), 0 ).r );

}
```

